using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class PredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidences { get; set; } = new();
}

public class EvaluationResponse
{
    public float MicroAccuracy { get; set; }
    public float MacroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public IEnumerable<CategoryMetric> PerCategoryMetrics { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly IDataView _trainingData;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);
        _trainingData = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(_trainingData);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract the ordered category labels so we can map Score[] indices to names
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(_trainingData.Schema)["Score"]
            .GetSlotNames(ref labelBuffer);
        _categoryLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidences = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length; i++)
        {
            confidences[_categoryLabels[i]] = prediction.Score[i];
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidences = confidences
        };
    }

    public EvaluationResponse Evaluate()
    {
        // Cross-validate with the training data to get realistic metrics
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(
            _trainingData, BuildPipeline(), numberOfFolds: 3, labelColumnName: "Label");

        var avgMetrics = cvResults.Select(r => r.Metrics).ToList();

        // Also evaluate on the full training set for per-class metrics
        var predictions = _model.Transform(_trainingData);
        var fullMetrics = _mlContext.MulticlassClassification.Evaluate(
            predictions, labelColumnName: "Label");

        var perCategory = fullMetrics.ConfusionMatrix.PerClassPrecision
            .Zip(fullMetrics.ConfusionMatrix.PerClassRecall, (p, r) => (Precision: p, Recall: r))
            .Select((pr, i) => new CategoryMetric
            {
                Category = _categoryLabels.Length > i ? _categoryLabels[i] : $"Class {i}",
                Precision = pr.Precision,
                Recall = pr.Recall,
                F1Score = 2 * pr.Precision * pr.Recall /
                          (pr.Precision + pr.Recall is 0 ? 1 : pr.Precision + pr.Recall)
            })
            .ToList();

        return new EvaluationResponse
        {
            MicroAccuracy = (float)avgMetrics.Average(m => m.MicroAccuracy),
            MacroAccuracy = (float)avgMetrics.Average(m => m.MacroAccuracy),
            LogLoss = (float)avgMetrics.Average(m => m.LogLoss),
            LogLossReduction = (float)avgMetrics.Average(m => m.LogLossReduction),
            PerCategoryMetrics = perCategory
        };
    }

    private EstimatorChain<Microsoft.ML.Transforms.KeyToValueMappingTransformer> BuildPipeline()
    {
        return _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    [HttpGet("evaluate")]
    public ActionResult<EvaluationResponse> Evaluate()
    {
        var metrics = _classifier.Evaluate();
        return Ok(metrics);
    }
}

