var predictions = _model.Transform(_trainingData);
var metrics = _mlContext.MulticlassClassification.Evaluate(
    predictions, labelColumnName: "Label");

var perCategory = metrics.ConfusionMatrix.PerClassPrecision
    .Zip(metrics.ConfusionMatrix.PerClassRecall, (p, r) => (Precision: p, Recall: r))
    .Select((pr, i) =>
    {
        double denom = pr.Precision + pr.Recall;
        return new CategoryMetric
        {
            Category = _categoryLabels.Length > i ? _categoryLabels[i] : $"Class {i}",
